md`Retrieved ${pointdata.length} locations from ${parquet_path}.`;
// Center initial Cesium view on PKAP Survey Area and also set Home to PKAP!
{
    const viewer = content.viewer;
    // PKAP Survey Area near Cyprus
    // Source: https://opencontext.org/subjects/48fd434c-f6d3...
    const pkapLat = 34.987406;
    const pkapLon = 33.708047;
    const delta = 0.3; // degrees padding around point
    const pkapRect = Cesium.Rectangle.fromDegrees(
        pkapLon - delta, // west (lon)
        pkapLat - delta, // south (lat)
        pkapLon + delta, // east (lon)
        pkapLat + delta  // north (lat)
    );

    // Make the Home button go to PKAP as well
    Cesium.Camera.DEFAULT_VIEW_RECTANGLE = pkapRect;
    Cesium.Camera.DEFAULT_VIEW_FACTOR = 0.5;

    // Apply camera after the first render to avoid resize/tab visibility issues
    const once = () =&gt; {
        viewer.camera.setView({ destination: pkapRect });
        viewer.scene.postRender.removeEventListener(once);
    };
    viewer.scene.postRender.addEventListener(once);
}
// Handle geocode search: fly to location and trigger queries
{
    if (searchGeoPid && searchGeoPid.trim() !== "") {
        const pid = searchGeoPid.trim();

        // Look up the geocode in the database
        const q = `SELECT pid, latitude, longitude FROM nodes WHERE otype='GeospatialCoordLocation' AND pid=?`;
        const result = await db.query(q, [pid]);

        if (result && result.length &gt; 0) {
            const geo = result[0];
            const viewer = content.viewer;

            // Fly camera to the location
            const position = Cesium.Cartesian3.fromDegrees(
                geo.longitude,
                geo.latitude,
                15000  // 15km altitude for good view
            );

            viewer.camera.flyTo({
                destination: position,
                duration: 2.0,  // 2 second flight
                complete: () =&gt; {
                    // After camera arrives, trigger the click to load data
                    mutable clickedPointId = pid;
                }
            });
        } else {
            // Geocode not found - could display error to user
            console.warn(`Geocode not found: ${pid}`);
        }
    }
}
// Handle optional classification button: recolor dots by type
// WIDE FORMAT: Uses p__sample_location and p__site_location columns directly
{
    if (classifyDots !== null) {
        console.log("Classifying dots by type (wide format)...");
        performance.mark('classify-start');

        try {
            // Wide format classification query - uses p__* columns directly
            const query = `
                WITH geo_classification AS (
                    SELECT
                        geo.pid,
                        MAX(CASE WHEN se.row_id IS NOT NULL THEN 1 ELSE 0 END) as is_sample_location,
                        MAX(CASE WHEN site.row_id IS NOT NULL THEN 1 ELSE 0 END) as is_site_location
                    FROM nodes geo
                    LEFT JOIN nodes se ON (
                        se.otype = 'SamplingEvent'
                        AND list_contains(se.p__sample_location, geo.row_id)
                    )
                    LEFT JOIN nodes site ON (
                        site.otype = 'SamplingSite'
                        AND list_contains(site.p__site_location, geo.row_id)
                    )
                    WHERE geo.otype = 'GeospatialCoordLocation'
                    GROUP BY geo.pid
                )
                SELECT
                    pid,
                    CASE
                        WHEN is_sample_location = 1 AND is_site_location = 1 THEN 'both'
                        WHEN is_sample_location = 1 THEN 'sample_location_only'
                        WHEN is_site_location = 1 THEN 'site_location_only'
                    END as location_type
                FROM geo_classification
            `;

            const classifications = await db.query(query);

            // Build lookup map: pid -&gt; location_type
            const typeMap = new Map();
            for (const row of classifications) {
                typeMap.set(row.pid, row.location_type);
            }

            // Color and size styling by location type
            const styles = {
                sample_location_only: {
                    color: Cesium.Color.fromCssColorString('#2E86AB'),
                    size: 3
                },  // Blue - field collection points
                site_location_only: {
                    color: Cesium.Color.fromCssColorString('#A23B72'),
                    size: 6
                },  // Purple - administrative markers
                both: {
                    color: Cesium.Color.fromCssColorString('#F18F01'),
                    size: 5
                }   // Orange - dual-purpose
            };

            // Update colors of existing points
            const points = content.points;
            for (let i = 0; i &lt; points.length; i++) {
                const point = points.get(i);
                const pid = point.id;
                const locationType = typeMap.get(pid);

                if (locationType && styles[locationType]) {
                    point.color = styles[locationType].color;
                    point.pixelSize = styles[locationType].size;
                }
            }

            performance.mark('classify-end');
            performance.measure('classification', 'classify-start', 'classify-end');
            const classifyTime = performance.getEntriesByName('classification')[0].duration;
            console.log(`Classification completed in ${classifyTime.toFixed(0)}ms - updated ${points.length} points`);
            console.log(`  - Blue (sample_location_only): field collection points`);
            console.log(`  - Purple (site_location_only): administrative markers`);
            console.log(`  - Orange (both): dual-purpose locations`);
        } catch (error) {
            console.error("Classification failed:", error);
            console.error("Error details:", error.message);

            // Show user-friendly message in browser console
            console.warn("⚠️ Color-coding failed due to a data loading issue.");
            console.warn("💡 Tip: This is an intermittent DuckDB-WASM issue with remote files.");
            console.warn("    Try clicking the button again, or use a local cached file for better reliability.");
            console.warn("    See the 'Using a local cached file' section above for instructions.");

            // Note: We don't show an alert() to avoid disrupting the user experience
            // The page remains functional, just without the color-coding
        }
    }
