                    &lt;td&gt;${labelHtml}&lt;/td&gt;
                    &lt;td&gt;${escapeHtml(place)}&lt;/td&gt;
                    &lt;td&gt;${escapeHtml(r.result_time || '')}&lt;/td&gt;
                    &lt;td&gt;${escapeHtml(lat)}&lt;/td&gt;
                    &lt;td&gt;${escapeHtml(lng)}&lt;/td&gt;
                &lt;/tr&gt;`;
